#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::TabularExtraction;
use File::Spec;

sub extract_metadata {
    my ($pdf_file) = @_;

    my $pdf = PDF::API2::open($pdf_file);
    my $info = $pdf->info;

    return {
        Author => $info->{Author},
        Title  => $info->{Title},
        Subject => $info->{Subject},
        Keywords => $info->{Keywords},
        Creator => $info->{Creator},
        Producer => $info->{Producer},
        CreationDate => $info->{CreationDate},
        ModDate => $info->{ModDate},
    };
}

sub extract_tables {
    my ($pdf_file) = @_;

    my $pdf = PDF::API2::open($pdf_file);
    my $pages = $pdf->pages;

    for my $page_num (1..$pages) {
        my $page = $pdf->page($page_num);
        my $text = $page->text;

        # Extraction de tableaux de texte
        my @tables = Text::TabularExtraction->extract_tables($text);

        if (@tables) {
            print "Tableau trouvé sur la page $page_num:\n";
            print "Tableau : ", Dumper(@tables);
        }
    }
}

